module FaceDetail =
  struct
    type nonrec t =
      {
      boundingBox: BoundingBox.t option
        [@ocaml.doc "Bounding box of the face. Default attribute."];
      ageRange: AgeRange.t option
        [@ocaml.doc
          "The estimated age range, in years, for the face. Low represents the lowest estimated age and High represents the highest estimated age."];
      smile: Smile.t option
        [@ocaml.doc
          "Indicates whether or not the face is smiling, and the confidence level in the determination."];
      eyeglasses: Eyeglasses.t option
        [@ocaml.doc
          "Indicates whether or not the face is wearing eye glasses, and the confidence level in the determination."];
      sunglasses: Sunglasses.t option
        [@ocaml.doc
          "Indicates whether or not the face is wearing sunglasses, and the confidence level in the determination."];
      gender: Gender.t option
        [@ocaml.doc "The predicted gender of a detected face."];
      beard: Beard.t option
        [@ocaml.doc
          "Indicates whether or not the face has a beard, and the confidence level in the determination."];
      mustache: Mustache.t option
        [@ocaml.doc
          "Indicates whether or not the face has a mustache, and the confidence level in the determination."];
      eyesOpen: EyeOpen.t option
        [@ocaml.doc
          "Indicates whether or not the eyes on the face are open, and the confidence level in the determination."];
      mouthOpen: MouthOpen.t option
        [@ocaml.doc
          "Indicates whether or not the mouth on the face is open, and the confidence level in the determination."];
      emotions: Emotions.t option
        [@ocaml.doc
          "The emotions that appear to be expressed on the face, and the confidence level in the determination. The API is only making a determination of the physical appearance of a person's face. It is not a determination of the person\226\128\153s internal emotional state and should not be used in such a way. For example, a person pretending to have a sad face might not be sad emotionally."];
      landmarks: Landmarks.t option
        [@ocaml.doc
          "Indicates the location of landmarks on the face. Default attribute."];
      pose: Pose.t option
        [@ocaml.doc
          "Indicates the pose of the face as determined by its pitch, roll, and yaw. Default attribute."];
      quality: ImageQuality.t option
        [@ocaml.doc
          "Identifies image brightness and sharpness. Default attribute."];
      confidence: Percent.t option
        [@ocaml.doc
          "Confidence level that the bounding box contains a face (and not a different object such as a tree). Default attribute."];
      faceOccluded: FaceOccluded.t option
        [@ocaml.doc
          "FaceOccluded should return \"true\" with a high confidence score if a detected face\226\128\153s eyes, nose, and mouth are partially captured or if they are covered by masks, dark sunglasses, cell phones, hands, or other objects. FaceOccluded should return \"false\" with a high confidence score if common occurrences that do not impact face verification are detected, such as eye glasses, lightly tinted sunglasses, strands of hair, and others."];
      eyeDirection: EyeDirection.t option
        [@ocaml.doc
          "Indicates the direction the eyes are gazing in, as defined by pitch and yaw."]}
    let make ?boundingBox =
      fun ?ageRange ->
        fun ?smile ->
          fun ?eyeglasses ->
            fun ?sunglasses ->
              fun ?gender ->
                fun ?beard ->
                  fun ?mustache ->
                    fun ?eyesOpen ->
                      fun ?mouthOpen ->
                        fun ?emotions ->
                          fun ?landmarks ->
                            fun ?pose ->
                              fun ?quality ->
                                fun ?confidence ->
                                  fun ?faceOccluded ->
                                    fun ?eyeDirection ->
                                      fun () ->
                                        {
                                          boundingBox;
                                          ageRange;
                                          smile;
                                          eyeglasses;
                                          sunglasses;
                                          gender;
                                          beard;
                                          mustache;
                                          eyesOpen;
                                          mouthOpen;
                                          emotions;
                                          landmarks;
                                          pose;
                                          quality;
                                          confidence;
                                          faceOccluded;
                                          eyeDirection
                                        }
    let to_value x =
      structure_to_value
        [("BoundingBox", (Option.map x.boundingBox ~f:BoundingBox.to_value));
        ("AgeRange", (Option.map x.ageRange ~f:AgeRange.to_value));
        ("Smile", (Option.map x.smile ~f:Smile.to_value));
        ("Eyeglasses", (Option.map x.eyeglasses ~f:Eyeglasses.to_value));
        ("Sunglasses", (Option.map x.sunglasses ~f:Sunglasses.to_value));
