        ("UserId", (Some (UserId.to_value x.userId)));
        ("FaceIds", (Some (UserFaceIdList.to_value x.faceIds)));
        ("UserMatchThreshold",
          (Option.map x.userMatchThreshold ~f:Percent.to_value));
        ("ClientRequestToken",
          (Option.map x.clientRequestToken ~f:ClientRequestToken.to_value))]
