          (Xml.child xml_arg0 "ClientRequestToken") in
      let userMatchThreshold =
        (Option.map ~f:Percent.of_xml)
          (Xml.child xml_arg0 "UserMatchThreshold") in
      let faceIds =
        UserFaceIdList.of_xml
