      let userId =
        UserId.of_xml (Xml.child_exn ~context:context_ xml_arg0 "UserId") in
      let collectionId =
        CollectionId.of_xml
          (Xml.child_exn ~context:context_ xml_arg0 "CollectionId") in
      make ?clientRequestToken ?userMatchThreshold ~faceIds ~userId
        ~collectionId ()
